export function getAgent(slug: string): Agent | undefined {
  return agents.find((a) => a.slug === slug);
}
export function getCategory(slug: string): Category | undefined {
  return categories.find((c) => c.slug === slug);
}
export function getCategoryById(id: string): Category | undefined {
  return categories.find((c) => c.id === id);
}
export function getAgentsByCategory(categoryId: string): Agent[] {
  return agents.filter((a) => a.category_id === categoryId && a.status === "approved");
}
export function getFeaturedAgents(): Agent[] {
  return agents.filter((a) => a.featured && a.status === "approved");
}
export function getTopRatedAgents(limit = 10): Agent[] {
  return [...agents].filter((a) => a.status === "approved").sort((a, b) => a.name.localeCompare(b.name)).slice(0, limit);
}
export function searchAgents(query: string): Agent[] {
  const q = query.toLowerCase();
  return agents.filter((a) => a.status === "approved" && (a.name.toLowerCase().includes(q) || a.tagline.toLowerCase().includes(q) || a.description.toLowerCase().includes(q) || a.capabilities.some((c) => c.toLowerCase().includes(q)) || a.tools.some((t) => t.toLowerCase().includes(q))));
}
